import{_ as n,o as h,c as i,ai as o}from"./chunks/framework.CJDL-GS7.js";const d=JSON.parse('{"title":"Mở phòng trực tuyến","description":"","frontmatter":{},"headers":[],"relativePath":"manage-live.md","filePath":"manage-live.md","lastUpdated":null}'),r={name:"manage-live.md"};function a(c,t,g,s,l,e){return h(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="mo-phong-truc-tuyen" tabindex="-1">Mở phòng trực tuyến <a class="header-anchor" href="#mo-phong-truc-tuyen" aria-label="Permalink to &quot;Mở phòng trực tuyến&quot;">​</a></h1><p>Tính năng phòng trực tuyến cho phép giáo viên tổ chức buổi học livestream với học sinh theo thời gian thực.</p><h2 id="tao-phong-hoc" tabindex="-1">Tạo phòng học <a class="header-anchor" href="#tao-phong-hoc" aria-label="Permalink to &quot;Tạo phòng học&quot;">​</a></h2><ol><li>Vào <strong>Học trực tuyến</strong> → nhấn <strong>Tạo phòng mới</strong></li><li>Điền thông tin: <ul><li><strong>Tiêu đề buổi học</strong> — VD: &quot;Ôn tập Toán chương 3 — Lớp 10A1&quot;</li><li><strong>Lớp học</strong> — Chọn lớp tham gia</li><li><strong>Thời gian bắt đầu</strong> — Lên lịch trước hoặc mở ngay</li><li><strong>Mô tả</strong> — Nội dung sẽ dạy (hiển thị cho học sinh)</li></ul></li><li>Nhấn <strong>Tạo phòng</strong></li></ol><h2 id="bat-đau-buoi-hoc" tabindex="-1">Bắt đầu buổi học <a class="header-anchor" href="#bat-đau-buoi-hoc" aria-label="Permalink to &quot;Bắt đầu buổi học&quot;">​</a></h2><ol><li>Vào danh sách phòng → nhấn <strong>Mở phòng</strong></li><li>Trình duyệt yêu cầu quyền <strong>Camera</strong> và <strong>Microphone</strong> → nhấn <strong>Cho phép</strong></li><li>Kiểm tra camera và âm thanh trước khi bắt đầu</li><li>Nhấn <strong>Bắt đầu livestream</strong></li></ol><p>Học sinh trong lớp sẽ thấy phòng học chuyển sang trạng thái <strong>Đang diễn ra</strong> và có thể vào tham gia.</p><h2 id="trong-buoi-hoc" tabindex="-1">Trong buổi học <a class="header-anchor" href="#trong-buoi-hoc" aria-label="Permalink to &quot;Trong buổi học&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Công cụ</th><th>Chức năng</th></tr></thead><tbody><tr><td>🎙️ <strong>Tắt/bật mic</strong></td><td>Bật tắt microphone</td></tr><tr><td>📷 <strong>Tắt/bật camera</strong></td><td>Bật tắt camera</td></tr><tr><td>💬 <strong>Chat</strong></td><td>Nhắn tin và trả lời câu hỏi học sinh</td></tr><tr><td>👥 <strong>Danh sách</strong></td><td>Xem học sinh đang tham gia</td></tr><tr><td>✋ <strong>Giơ tay</strong></td><td>Danh sách học sinh đang chờ hỏi</td></tr><tr><td>🖥️ <strong>Chia sẻ màn hình</strong></td><td>Chiếu bài giảng, slide lên cho học sinh</td></tr></tbody></table><h2 id="ket-thuc-buoi-hoc" tabindex="-1">Kết thúc buổi học <a class="header-anchor" href="#ket-thuc-buoi-hoc" aria-label="Permalink to &quot;Kết thúc buổi học&quot;">​</a></h2><ol><li>Nhấn <strong>Kết thúc phòng học</strong></li><li>Xác nhận → phòng đóng lại, học sinh tự động bị thoát</li><li>Hệ thống lưu lại lịch sử buổi học (thời gian, số học sinh tham gia)</li></ol><div class="warning custom-block"><p class="custom-block-title">Lưu ý kỹ thuật</p><ul><li>Sử dụng <strong>Chrome</strong> hoặc <strong>Edge</strong> để có trải nghiệm tốt nhất</li><li>Kết nối internet tối thiểu <strong>10 Mbps upload</strong> để truyền video ổn định</li><li>Sử dụng tai nghe có mic để tránh tiếng vang</li></ul></div>',12)])])}const p=n(r,[["render",a]]);export{d as __pageData,p as default};
